"use client";
import * as React from "react";
import { accordionAnatomy } from "@tessera/core";
import { createStrictContext, useControllableState } from "../utils/hooks";
import { ChevronDownIcon } from "../utils/icons";

interface AccordionContextValue {
  openValues: string[];
  toggle: (value: string) => void;
  baseId: string;
}

const [AccordionProvider, useAccordionContext] =
  createStrictContext<AccordionContextValue>("Accordion");

interface AccordionItemContextValue {
  value: string;
  open: boolean;
  disabled?: boolean;
}

const [AccordionItemProvider, useAccordionItemContext] =
  createStrictContext<AccordionItemContextValue>("Accordion.Item");

export interface AccordionRootProps {
  /** Allow multiple items open at once. Default false. */
  multiple?: boolean;
  value?: string[];
  defaultValue?: string[];
  onValueChange?: (value: string[]) => void;
  children: React.ReactNode;
}

function AccordionRoot({
  multiple = false,
  value,
  defaultValue = [],
  onValueChange,
  children,
}: AccordionRootProps) {
  const [openValues, setOpenValues] = useControllableState({
    value,
    defaultValue,
    onChange: onValueChange,
  });
  const baseId = React.useId();

  function toggle(itemValue: string) {
    if (openValues.includes(itemValue)) {
      setOpenValues(openValues.filter((v) => v !== itemValue));
    } else {
      setOpenValues(multiple ? [...openValues, itemValue] : [itemValue]);
    }
  }

  return (
    <div {...accordionAnatomy.attrs("root")}>
      <AccordionProvider value={{ openValues, toggle, baseId }}>{children}</AccordionProvider>
    </div>
  );
}

export interface AccordionItemProps {
  value: string;
  disabled?: boolean;
  children: React.ReactNode;
}

function AccordionItem({ value, disabled, children }: AccordionItemProps) {
  const { openValues } = useAccordionContext();
  const open = openValues.includes(value);
  return (
    <div
      {...accordionAnatomy.attrs("item")}
      data-state={open ? "open" : "closed"}
      data-disabled={disabled || undefined}
    >
      <AccordionItemProvider value={{ value, open, disabled }}>{children}</AccordionItemProvider>
    </div>
  );
}

function AccordionTrigger({ children, ...rest }: React.ButtonHTMLAttributes<HTMLButtonElement>) {
  const { toggle, baseId } = useAccordionContext();
  const item = useAccordionItemContext();
  return (
    <h3 {...accordionAnatomy.attrs("header")}>
      <button
        type="button"
        {...accordionAnatomy.attrs("trigger")}
        id={`${baseId}-trigger-${item.value}`}
        aria-expanded={item.open}
        aria-controls={`${baseId}-content-${item.value}`}
        data-state={item.open ? "open" : "closed"}
        disabled={item.disabled}
        onClick={() => toggle(item.value)}
        {...rest}
      >
        <span>{children}</span>
        <span {...accordionAnatomy.attrs("indicator")}>
          <ChevronDownIcon />
        </span>
      </button>
    </h3>
  );
}

function AccordionContent({ children, ...rest }: React.HTMLAttributes<HTMLDivElement>) {
  const { baseId } = useAccordionContext();
  const item = useAccordionItemContext();
  if (!item.open) return null;
  return (
    <div
      {...accordionAnatomy.attrs("content")}
      role="region"
      id={`${baseId}-content-${item.value}`}
      aria-labelledby={`${baseId}-trigger-${item.value}`}
      data-state="open"
      {...rest}
    >
      {children}
    </div>
  );
}

export const Accordion = {
  Root: AccordionRoot,
  Item: AccordionItem,
  Trigger: AccordionTrigger,
  Content: AccordionContent,
};

@layer tessera.recipes {
  [data-scope="accordion"][data-part="root"] {
    display: flex;
    flex-direction: column;
    border: 1px solid var(--ts-border-muted);
    border-radius: var(--ts-radius-lg);
    overflow: hidden;
  }

  [data-scope="accordion"][data-part="item"] {
    border-bottom: 1px solid var(--ts-border-muted);
  }

  [data-scope="accordion"][data-part="item"]:last-child {
    border-bottom: none;
  }

  [data-scope="accordion"][data-part="header"] {
    margin: 0;
  }

  [data-scope="accordion"][data-part="trigger"] {
    appearance: none;
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    border: none;
    background: var(--ts-bg-surface);
    color: var(--ts-fg-default);
    font-size: var(--ts-font-size-sm);
    font-weight: var(--ts-font-weight-medium);
    padding: var(--ts-space-3) var(--ts-space-4);
    cursor: pointer;
    text-align: left;
    transition: background-color var(--ts-duration-fast) var(--ts-easing-standard);
  }

  [data-scope="accordion"][data-part="trigger"]:hover {
    background: var(--ts-bg-subtle);
  }

  [data-scope="accordion"][data-part="indicator"] {
    display: inline-flex;
    color: var(--ts-fg-muted);
    transition: transform var(--ts-duration-normal) var(--ts-easing-standard);
  }

  [data-scope="accordion"][data-part="trigger"][data-state="open"] [data-part="indicator"] {
    transform: rotate(180deg);
  }

  [data-scope="accordion"][data-part="content"] {
    padding: var(--ts-space-3) var(--ts-space-4);
    background: var(--ts-bg-canvas);
    color: var(--ts-fg-muted);
    font-size: var(--ts-font-size-sm);
    line-height: var(--ts-font-leading-normal);
  }
}
